import './index.css'

const statusClass=(s:OrderStatus)=>`status ${s.replaceAll(' ','-').toLowerCase()}`
const todayLocal=()=>{const date=new Date();return `${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,'0')}-${String(date.getDate()).padStart(2,'0')}`}
const makeReceiptNumber=(movements:AppState['movements'])=>{const max=Math.max(0,...movements.map(m=>m.orderNumber.match(/^PR-(\d{4})$/)?.[1]).filter(Boolean).map(Number));return `PR-${String(max+1).padStart(4,'0')}`}
const packingNumber=(order:Order)=>order.number.replace(/^PG-/, 'SP-')
type ReceiptGroup={number:string;date:string;lines:Movement[];party:string;note:string}
const receiptGroups=(movements:Movement[]):ReceiptGroup[]=>{
 const groups=new Map<string,Movement[]>()
 movements.filter(m=>m.type==='Влез'&&/^PR-\d{4}$/.test(m.orderNumber)).forEach(m=>groups.set(m.orderNumber,[...(groups.get(m.orderNumber)||[]),m]))
 return [...groups].map(([number,lines])=>({number,date:lines[0].date,lines,party:lines.map(line=>line.party).find(Boolean)||'',note:lines.map(line=>line.note).find(Boolean)||''})).sort((a,b)=>Number(b.number.slice(3))-Number(a.number.slice(3)))
}
const localDemo=import.meta.env.DEV&&new URLSearchParams(window.location.search).has('local-demo')
const localMode=!syncEnabled||localDemo

function App(){
 const {state,setState,session,profile,authReady,syncStatus,syncError,recordAudit}=useSyncedState()
 const [page,setPage]=useState('dashboard')
 const [selected,setSelected]=useState<string|null>(null)
 const [showOrder,setShowOrder]=useState(false)
 const [editingOrderId,setEditingOrderId]=useState<string|null>(null)
 const [showEntry,setShowEntry]=useState(false)
 const [showReceipt,setShowReceipt]=useState(false)
 const [editingReceiptNumber,setEditingReceiptNumber]=useState<string|null>(null)
 const [receiptToPrint,setReceiptToPrint]=useState<ReceiptGroup|null>(null)
 const [printMode,setPrintMode]=useState<'packing'|'receipt'>('packing')
 const [printQrDataUrl,setPrintQrDataUrl]=useState('')
 const [query,setQuery]=useState('')
 const [selectedLoadIds,setSelectedLoadIds]=useState<Set<string>>(()=>new Set())
 const [linkedOrderId]=useState(()=>new URLSearchParams(window.location.search).get('order'))
 const [linkedOrderHandled,setLinkedOrderHandled]=useState(false)
 const selectedOrder=state.orders.find(o=>o.id===selected)||null
 const packingOrders=state.orders.filter(order=>['Чека залиха','Нова','Во подготовка','Спакувана'].includes(order.status))
 const packingOrder=selectedOrder&&packingOrders.some(order=>order.id===selectedOrder.id)?selectedOrder:(packingOrders[0]||null)
 const editingOrder=state.orders.find(o=>o.id===editingOrderId)||null
 const editingReceipt=receiptGroups(state.movements).find(receipt=>receipt.number===editingReceiptNumber)||null
 const r=useMemo(()=>reserved(state),[state]); const a=useMemo(()=>available(state),[state])
 const adminEmail=(session?.user.email||profile?.email||'').toLowerCase()
 const isAdmin=profile?.role==='admin'||adminEmail==='vlatko_dinev@hotmail.com'
 useEffect(()=>{if(linkedOrderHandled||!linkedOrderId)return;const linked=state.orders.find(order=>order.id===linkedOrderId);if(linked){setSelected(linked.id);setPage('packing');setLinkedOrderHandled(true)}},[linkedOrderHandled,linkedOrderId,state.orders])
 if(!authReady&&!localMode)return <div className="auth-shell"><div className="auth-card"><div className="auth-logo">MP</div><h1>MAGACIN PRO</h1><p>Се поврзува со заедничката база...</p></div></div>
 if(!session&&!localMode)return <AuthScreen/>
 const patchPacked=(o:Order,key:keyof Order['packed'],value:boolean)=>{
  const updated=updatePackedItem(state,o.id,key,value)
  if(!updated){alert('Нема доволно залиха за оваа нарачка.');return}
  setState(updated)
  void recordAudit('order.packing_checked','order',o.id,{number:o.number,item:key,checked:value,auto_packed:updated.orders.find(order=>order.id===o.id)?.status==='Спакувана'&&o.status!=='Спакувана'})
 }
 const changeStatus=(o:Order,next:OrderStatus)=>{
  if(next===o.status)return
  if(!allowedTransitions[o.status].includes(next)){alert(`Не е дозволен премин од „${o.status}“ во „${next}“.`);return}
  if(next==='Спакувана'&&!allPacked(o)){alert('Прво означи ги сите ставки како спакувани.');return}
  if((next==='Нова'||next==='Во подготовка')&&!o.stockDeducted&&!canReserveOrder({...state,orders:state.orders.filter(order=>order.id!==o.id)},o)){alert('Нема доволно слободна залиха за повторно активирање.');return}
  if(next==='Откажана'){
   if(o.stockDeducted&&!confirm('Количината ќе се врати во магацин. Продолжи?'))return
   const cancelled=returnOrderStock(state,o)
   setState(reconcileWaitingOrders({...cancelled,orders:cancelled.orders.map(order=>order.id===o.id?{...order,status:'Откажана'}:order)}))
   void recordAudit('order.cancelled','order',o.id,{number:o.number,from:o.status,stock_returned:o.stockDeducted});return
  }
  const targetDeducted=deductStatuses.has(next)
  if(o.stockDeducted&&!targetDeducted){
   const restored=returnOrderStock(state,o)
   const updated={...restored,orders:restored.orders.map(order=>order.id===o.id?{...order,status:next,stockDeducted:false}:order)}
   setState(reconcileWaitingOrders(updated));void recordAudit('order.status_rolled_back','order',o.id,{number:o.number,from:o.status,to:next,stock_returned:true});return
  }
  if(targetDeducted&&!o.stockDeducted){
   const updated=deductOrderStock(state,o,next);if(!updated){alert('Нема доволно залиха за оваа нарачка.');return}
   setState(updated);void recordAudit('order.status_changed','order',o.id,{number:o.number,from:o.status,to:next});return
  }
  setState(current=>({...current,orders:current.orders.map(order=>order.id===o.id?{...order,status:next}:order)}))
  void recordAudit('order.status_changed','order',o.id,{number:o.number,from:o.status,to:next})
 }
 const advanceOrder=(o:Order)=>{
  if(o.status==='Чека залиха'){alert('Нарачката сè уште чека залиха и не може да продолжи.');return}
  if(o.status==='Нова'||o.status==='Во подготовка'){
   const confirmed={...o,packed:{regular025:true,bib15:true,free025:true,free15:true,flyers:true}}
   const staged={...state,orders:state.orders.map(order=>order.id===o.id?confirmed:order)}
   const updated=deductOrderStock(staged,confirmed,'Спакувана')
   if(!updated){alert('Нема доволно залиха за да се потврди целата нарачка.');return}
   setState(updated);void recordAudit('order.qr_status_advanced','order',o.id,{number:o.number,from:o.status,to:'Спакувана'});return
  }
  const next:Partial<Record<OrderStatus,OrderStatus>>={Спакувана:'Испратена',Излезена:'Испратена',Испратена:'Доставена'}
  const target=next[o.status]
  if(target){changeStatus(o,target);void recordAudit('order.qr_status_advanced','order',o.id,{number:o.number,from:o.status,to:target})}
 }
 const deleteOrder=(id:string)=>{const order=state.orders.find(item=>item.id===id);if(!order||!confirm('Да се избрише нарачката?'))return;setState(s=>({...s,orders:s.orders.filter(item=>item.id!==id)}));void recordAudit('order.deleted','order',id,{number:order.number,client:order.client})}
 const saveNewOrder=(o:Order)=>{const saved={...o,status:(canReserveOrder(state,o)?'Нова':'Чека залиха') as OrderStatus};setState(s=>({...s,orders:[saved,...s.orders],clients:s.clients.some(c=>c.name.toLowerCase()===saved.client.toLowerCase())?s.clients:[...s.clients,{id:crypto.randomUUID(),name:saved.client,city:saved.city,phone:'',contactPerson:'',address:''}]}));void recordAudit('order.created','order',saved.id,{number:saved.number,client:saved.client,city:saved.city,status:saved.status});setShowOrder(false)}
 const editOrder=(o:Order)=>{if(o.stockDeducted&&!isAdmin){alert('Само администратор може да менува нарачка откако залихата е одземена.');return}if(o.stockDeducted&&!confirm('Оваа нарачка е веќе спакувана. При зачувување, старата количина ќе се врати и исправената повторно ќе се одземе. Продолжи?'))return;setEditingOrderId(o.id)}
 const saveEditedOrder=(candidate:Order)=>{
  const original=state.orders.find(order=>order.id===candidate.id);if(!original)return
  const resetPacked={regular025:false,bib15:false,free025:false,free15:false,flyers:false}
  let corrected={...candidate,status:original.status,stockDeducted:false,packed:original.stockDeducted?{regular025:true,bib15:true,free025:true,free15:true,flyers:true}:resetPacked}
  let next:AppState
  if(original.stockDeducted){
   if(!isAdmin){alert('Само администратор може да ја направи оваа исправка.');return}
   const restored=returnOrderStock(state,original)
   const staged={...restored,orders:restored.orders.map(order=>order.id===original.id?corrected:order)}
   const rededucted=deductOrderStock(staged,corrected,original.status)
   if(!rededucted){alert('Исправката не може да се зачува бидејќи нема доволно залиха за новата количина.');return}
   next=rededucted
  }else{
   const withoutOriginal={...state,orders:state.orders.filter(order=>order.id!==original.id)}
   corrected={...corrected,status:canReserveOrder(withoutOriginal,corrected)?(original.status==='Чека залиха'?'Нова':original.status):'Чека залиха'}
   next={...state,orders:state.orders.map(order=>order.id===original.id?corrected:order)}
  }
  if(!next.clients.some(client=>client.name.trim().toLowerCase()===corrected.client.trim().toLowerCase()))next={...next,clients:[...next.clients,{id:crypto.randomUUID(),name:corrected.client,city:corrected.city,phone:'',contactPerson:'',address:''}]}
  setState(next);setEditingOrderId(null)
  void recordAudit('order.corrected','order',original.id,{number:original.number,from:`${original.client}; 0.25=${original.qty025}+${original.free025}; BiB=${original.qty15}+${original.free15||0}; flyers=${original.flyers}`,to:`${corrected.client}; 0.25=${corrected.qty025}+${corrected.free025}; BiB=${corrected.qty15}+${corrected.free15||0}; flyers=${corrected.flyers}`,stock_recalculated:original.stockDeducted})
 }
 const saveStockEntry=(p:ProductKey,t:MovementType,pack:number,pieces:number,party:string,note:string,date:string)=>{const delta=(t==='Излез'||t==='Оштетување')?-1:1;const total=p==='p025'?pack*15+pieces:p==='p15'?pack*6+pieces:pieces;const current=p==='p025'?state.warehouse.p025.total:p==='p15'?state.warehouse.p15.total:state.warehouse.flyers;if(current+delta*total<0){alert('Не е дозволена негативна залиха.');return}setState(s=>reconcileWaitingOrders({...s,warehouse:p==='p025'?{...s.warehouse,p025:normalize(s.warehouse.p025.total+delta*total,15)}:p==='p15'?{...s.warehouse,p15:normalize(s.warehouse.p15.total+delta*total,6)}:{...s.warehouse,flyers:s.warehouse.flyers+delta*total},movements:[{id:crypto.randomUUID(),date,product:p,type:t,packages:pack,pieces,party,orderNumber:'',note},...s.movements]}));void recordAudit('stock.movement','stock',p,{type:t,packages:pack,pieces,party});setShowEntry(false)}
 const saveReceipt=(p:ProductKey,pack:number,pieces:number,workers:string,note:string,date:string)=>{const total=p==='p025'?pack*15+pieces:p==='p15'?pack*6+pieces:pieces;if(total<=0){alert('Внеси примена количина.');return}const receiptNumber=makeReceiptNumber(state.movements);setState(s=>reconcileWaitingOrders({...s,warehouse:p==='p025'?{...s.warehouse,p025:normalize(s.warehouse.p025.total+total,15)}:p==='p15'?{...s.warehouse,p15:normalize(s.warehouse.p15.total+total,6)}:{...s.warehouse,flyers:s.warehouse.flyers+total},movements:[{id:crypto.randomUUID(),date,product:p,type:'Влез',packages:pack,pieces,party:workers,orderNumber:receiptNumber,note},...s.movements]}));void recordAudit('stock.receipt','receipt',receiptNumber,{product:productName(p),packages:pack,pieces,workers});setShowReceipt(false)}
 const saveEditedReceipt=(receipt:ReceiptGroup,lines:Movement[],workers:string,note:string,date:string)=>{
  const total=(line:Movement)=>line.product==='p025'?line.packages*15+line.pieces:line.product==='p15'?line.packages*6+line.pieces:line.pieces
  const oldTotals={p025:0,p15:0,flyers:0};receipt.lines.forEach(line=>{oldTotals[line.product]+=total(line)})
  const newTotals={p025:0,p15:0,flyers:0};lines.forEach(line=>{newTotals[line.product]+=total(line)})
  const nextTotals={p025:state.warehouse.p025.total-oldTotals.p025+newTotals.p025,p15:state.warehouse.p15.total-oldTotals.p15+newTotals.p15,flyers:state.warehouse.flyers-oldTotals.flyers+newTotals.flyers}
  if(nextTotals.p025<0||nextTotals.p15<0||nextTotals.flyers<0){alert('Оваа измена би направила негативна залиха. Провери ги количините.');return}
  const changedLines=lines.map(line=>({...line,date,party:workers,note,orderNumber:receipt.number,type:'Влез' as const}))
  setState(current=>reconcileWaitingOrders({...current,warehouse:{p025:normalize(nextTotals.p025,15),p15:normalize(nextTotals.p15,6),flyers:nextTotals.flyers},movements:[...changedLines,...current.movements.filter(line=>line.orderNumber!==receipt.number)]}))
  setEditingReceiptNumber(null);void recordAudit('stock.receipt_corrected','receipt',receipt.number,{before:JSON.stringify(oldTotals),after:JSON.stringify(newTotals),workers,date})
 }
 const printOrder=async(o:Order)=>{setSelected(o.id);setPrintMode('packing');setPrintQrDataUrl(await createOrderQrDataUrl(o.id));setTimeout(()=>window.print(),100)}
 const printReceipt=(receipt:ReceiptGroup)=>{setReceiptToPrint(receipt);setPrintMode('receipt');setPrintQrDataUrl('');setTimeout(()=>window.print(),50)}
 return <div className="app"><SideNav page={page} setPage={setPage} isAdmin={isAdmin}/><main className="main">
  {page==='dashboard'&&<Dashboard state={state} r={r} a={a} setPage={setPage} openOrder={id=>{setSelected(id);setPage('packing')}} openPacked={()=>{setSelected(state.orders.find(o=>o.status==='Спакувана')?.id||null);setPage('packing')}}/>}
  {page==='orders'&&<Orders state={state} query={query} setQuery={setQuery} selectedIds={selectedLoadIds} setSelectedIds={setSelectedLoadIds} onOpen={id=>{setSelected(id);setPage('packing')}} onNew={()=>setShowOrder(true)} onEdit={editOrder} onDelete={isAdmin?deleteOrder:undefined}/>}
  {page==='packing'&&<Packing order={packingOrder} onSelect={setSelected} orders={packingOrders} patchPacked={patchPacked} changeStatus={changeStatus} advanceOrder={advanceOrder} printOrder={printOrder} onEdit={editOrder} fromQr={Boolean(linkedOrderId&&packingOrder?.id===linkedOrderId)}/>}
  {page==='warehouse'&&<WarehousePage state={state} onEntry={()=>setShowEntry(true)} onReceipt={()=>setShowReceipt(true)} onEditReceipt={receipt=>setEditingReceiptNumber(receipt.number)}/>}
  {page==='clients'&&<ClientsPage state={state}/>}
  {page==='movements'&&<MovementsPage state={state}/>}
  {page==='reports'&&<ReportsPage state={state}/>}
  {page==='printing'&&<PrintingPage state={state} printOrder={printOrder} printReceipt={printReceipt} changeStatus={changeStatus} editReceipt={receipt=>setEditingReceiptNumber(receipt.number)}/>}
  {page==='admin'&&isAdmin&&session&&<AdminPage currentUserId={session.user.id}/>}
  {page==='settings'&&<SettingsPage
   syncStatus={syncStatus}
   syncError={syncError}
   email={session?.user.email||'Локален тест'}
   role={profile?.role||'operator'}
   isAdmin={isAdmin}
   openAdmin={()=>setPage('admin')}
   onReset={isAdmin?()=>{if(confirm('Да се вратат демо податоците? Сите тековни податоци ќе се избришат.')){setState(hydrateState(demoState()));setSelected(null);void recordAudit('app.demo_reset','app',null,{})}}:undefined}
  />}
 </main><BottomNav page={page} setPage={setPage}/>
 {showOrder&&<NewOrder state={state} onClose={()=>setShowOrder(false)} onSave={saveNewOrder}/>}
 {editingOrder&&<EditOrder state={state} order={editingOrder} onClose={()=>setEditingOrderId(null)} onSave={saveEditedOrder}/>}
 {showEntry&&<StockEntry onClose={()=>setShowEntry(false)} onSave={saveStockEntry}/>}
 {showReceipt&&<ReceiptEntry state={state} onClose={()=>setShowReceipt(false)} onSave={saveReceipt}/>}
 {editingReceipt&&<EditReceipt receipt={editingReceipt} onClose={()=>setEditingReceiptNumber(null)} onSave={saveEditedReceipt}/>}
 <div className="print-only">{printMode==='packing'&&selectedOrder?<PackingPrint o={selectedOrder} qrDataUrl={printQrDataUrl}/>:printMode==='receipt'&&receiptToPrint?<ReceiptPrint receipt={receiptToPrint}/>:null}</div>
 </div>
}

function AuthScreen(){
 const [fullName,setFullName]=useState('')
 const [email,setEmail]=useState('')
 const [password,setPassword]=useState('')
 const [mode,setMode]=useState<'login'|'signup'>('login')
 const [busy,setBusy]=useState(false)
 const [message,setMessage]=useState('')
 const submit=async(e:FormEvent)=>{
  e.preventDefault();setBusy(true);setMessage('')
  const result=mode==='login'
   ?await supabase.auth.signInWithPassword({email,password})
   :await supabase.auth.signUp({email,password,options:{data:{full_name:fullName.trim()}}})
  setBusy(false)
  if(result.error){setMessage(result.error.message);return}
  if(mode==='signup'&&!result.data.session)setMessage('Провери ја е-поштата и потврди ја регистрацијата, па најави се.')
 }
 return <div className="auth-shell"><form className="auth-card" onSubmit={submit}><div className="auth-logo">MP</div><span>MAGACIN PRO</span><h1>{mode==='login'?'Најава':'Нов профил'}</h1><p>Секој вработен користи свој профил, а сите работат во истиот заеднички магацин.</p>{mode==='signup'&&<label>Име и презиме<input required autoComplete="name" value={fullName} onChange={e=>setFullName(e.target.value)}/></label>}<label>Е-пошта<input type="email" required autoComplete="email" value={email} onChange={e=>setEmail(e.target.value)}/></label><label>Лозинка<input type="password" required minLength={6} autoComplete={mode==='login'?'current-password':'new-password'} value={password} onChange={e=>setPassword(e.target.value)}/></label>{message&&<div className="auth-message">{message}</div>}<button className="primary auth-submit" disabled={busy}><LogIn size={18}/>{busy?'Почекај...':mode==='login'?'Најави се':'Регистрирај се'}</button><button type="button" className="auth-switch" onClick={()=>{setMode(mode==='login'?'signup':'login');setMessage('')}}>{mode==='login'?'Немаш профил? Регистрирај се':'Имаш профил? Најави се'}</button></form></div>
}

function Dashboard({state,r,a,setPage,openOrder,openPacked}:{state:AppState;r:{p025:number;p15:number;flyers:number};a:{p025:number;p15:number;flyers:number};setPage:(p:string)=>void;openOrder:(id:string)=>void;openPacked:()=>void}){const packed=state.orders.filter((order:Order)=>order.status==='Спакувана').length,sent=state.orders.filter((order:Order)=>['Излезена','Испратена','Доставена'].includes(order.status)).length,waiting=state.orders.filter((order:Order)=>order.status==='Чека залиха').length;return <><PageHeader title="Контролна табла" action={<button className="primary" onClick={()=>setPage('orders')}><CirclePlus size={18}/> Нова нарачка</button>}/><div className="hero"><div className="hero-copy"><span className="hero-eyebrow">Магацин во реално време</span><h2 className="hero-title"><span>Пакувај.</span><span>Следи.</span><span>Испорачај.</span></h2></div><div className="pulse"><i/> Системот е активен</div></div><div className="stock-grid"><StockCard title={productName('p025')} packs={state.warehouse.p025.packages} pieces={state.warehouse.p025.pieces} total={state.warehouse.p025.total} reserved={r.p025} available={a.p025} perPackage={15} onClick={()=>setPage('warehouse')}/><StockCard title={productName('p15')} packs={state.warehouse.p15.packages} pieces={state.warehouse.p15.pieces} total={state.warehouse.p15.total} reserved={r.p15} available={a.p15} perPackage={6} onClick={()=>setPage('warehouse')}/><StockCard title="Флаери" packs={0} pieces={state.warehouse.flyers} total={state.warehouse.flyers} reserved={r.flyers} available={a.flyers} perPackage={0} onClick={()=>setPage('warehouse')}/></div><div className="metric-grid"><Metric label="Активни нарачки" value={state.orders.filter((order:Order)=>activeStatuses.has(order.status)).length} onClick={()=>setPage('orders')}/><Metric label="Чекаат залиха" value={waiting} onClick={()=>setPage('orders')}/><Metric label="Спакувани" value={packed} onClick={openPacked}/><Metric label="Испратени/излезени" value={sent} onClick={()=>setPage('movements')}/></div><Card><div className="section-title"><div><h3>Следни за пакување</h3><p>Нарачките што чекаат залиха се прикажани први</p></div><button className="ghost" onClick={()=>setPage('packing')}>Отвори пакување <ChevronRight size={16}/></button></div><div className="compact-list">{state.orders.filter((order:Order)=>activeStatuses.has(order.status)).toSorted((x:Order,y:Order)=>(x.status==='Чека залиха'?0:1)-(y.status==='Чека залиха'?0:1)).slice(0,5).map((order:Order)=><button type="button" key={order.id} onClick={()=>openOrder(order.id)}><span><strong>{order.client}</strong><small>{order.city} • {order.number}</small></span><span className={statusClass(order.status)}>{order.status}</span></button>)}</div></Card></>}
const quantityBreakdown=(total:number,perPackage:number)=>perPackage>0?`${Math.floor(Math.max(0,total)/perPackage)} пак. + ${Math.max(0,total)%perPackage} пар.`:`${Math.max(0,total)} пар.`
const StockCard=({title,packs,pieces,total,reserved,available,perPackage,onClick}:{title:string;packs:number;pieces:number;total:number;reserved:number;available:number;perPackage:number;onClick?:()=>void})=>{const content=<><div className="stock-icon"><Package/></div><div className="stock-top"><h3>{title}</h3><strong>{total}</strong></div><div className="stock-split"><span><b>{packs}</b> пакети</span><span><b>{pieces}</b> парчиња</span></div><div className="stock-math"><span>Во магацин <b>{total}</b><small>{quantityBreakdown(total,perPackage)}</small></span><span>Закажано <b>{reserved}</b><small>{quantityBreakdown(reserved,perPackage)}</small></span><span>Ќе остане <b>{available}</b><small>{quantityBreakdown(available,perPackage)}</small></span></div></>;return onClick?<button type="button" className="card stock-card dashboard-link" onClick={onClick}>{content}</button>:<Card className="stock-card">{content}</Card>}
const Metric=({label,value,onClick}:{label:string;value:number;onClick?:()=>void})=>onClick?<button type="button" className="card metric dashboard-link" onClick={onClick}><span>{label}</span><strong>{value}</strong></button>:<Card className="metric"><span>{label}</span><strong>{value}</strong></Card>

type OrderView='new'|'packed'|'sent'|'delivered'|'cancelled'|'loading'
const orderViewLabels:Record<OrderView,string>={new:'Нови',packed:'Спакувани',sent:'Испратени',delivered:'Доставени',cancelled:'Откажани',loading:'План за товарење'}
const orderMatchesView=(order:Order,view:OrderView)=>view==='new'?['Чека залиха','Нова','Во подготовка'].includes(order.status):view==='packed'?order.status==='Спакувана':view==='sent'?['Излезена','Испратена'].includes(order.status):view==='delivered'?order.status==='Доставена':view==='cancelled'?order.status==='Откажана':['Чека залиха','Нова','Во подготовка','Спакувана'].includes(order.status)

function Orders({state,query,setQuery,selectedIds,setSelectedIds,onOpen,onNew,onEdit,onDelete}:{state:AppState;query:string;setQuery:(value:string)=>void;selectedIds:Set<string>;setSelectedIds:(value:Set<string>)=>void;onOpen:(id:string)=>void;onNew:()=>void;onEdit:(order:Order)=>void;onDelete?:(id:string)=>void}){
 const [view,setView]=useState<OrderView>('new')
 const searched=state.orders.filter((order:Order)=>(order.client+' '+order.city+' '+order.number).toLowerCase().includes(query.toLowerCase()))
 const list=searched.filter(order=>orderMatchesView(order,view)).toSorted((a:Order,b:Order)=>b.date.localeCompare(a.date)||b.number.localeCompare(a.number))
 const loadingOrders=state.orders.filter(order=>orderMatchesView(order,'loading'))
 const selected=loadingOrders.filter(order=>selectedIds.has(order.id))
 const totals=selected.reduce((sum,order)=>{const qty=orderPieces(order);return {p025:sum.p025+qty.p025,p15:sum.p15+qty.p15,flyers:sum.flyers+qty.flyers}},{p025:0,p15:0,flyers:0})
 const remaining={p025:state.warehouse.p025.total-totals.p025,p15:state.warehouse.p15.total-totals.p15,flyers:state.warehouse.flyers-totals.flyers}
 const toggle=(id:string)=>{const next=new Set(selectedIds);next.has(id)?next.delete(id):next.add(id);setSelectedIds(next)}
 const choose=(orders:Order[])=>setSelectedIds(new Set(orders.map(order=>order.id)))
 const changeView=(next:OrderView)=>{setView(next);if(next!=='loading')setSelectedIds(new Set())}
 const counts=Object.fromEntries((Object.keys(orderViewLabels) as OrderView[]).map(key=>[key,state.orders.filter(order=>orderMatchesView(order,key)).length])) as Record<OrderView,number>
 const emptyText=view==='new'?'Нема нови нарачки.':view==='packed'?'Нема спакувани нарачки.':view==='sent'?'Нема испратени нарачки.':view==='delivered'?'Нема доставени нарачки.':view==='cancelled'?'Нема откажани нарачки.':'Нема нови или спакувани нарачки за товарење.'
 return <><PageHeader title="Нарачки" action={<button className="primary" onClick={onNew}><CirclePlus size={18}/> Нова нарачка</button>}/>
  <div className="status-tabs">{(Object.keys(orderViewLabels) as OrderView[]).map(key=><button key={key} className={view===key?'active':''} onClick={()=>changeView(key)}><span>{orderViewLabels[key]}</span><b>{counts[key]}</b></button>)}</div>
  {view==='loading'&&<Card className="loading-planner"><div className="section-title"><div><h3>План за товарење</h3><p>Тука се појавуваат само нови, во подготовка и спакувани нарачки.</p></div><strong>{selected.length} избрани</strong></div><div className="planner-actions"><button className="ghost" onClick={()=>choose(list)}>Избери ги прикажаните</button><button className="ghost" onClick={()=>choose(list.filter(order=>order.status==='Спакувана'))}>Само спакувани</button><button className="ghost" onClick={()=>choose(list.filter(order=>['Чека залиха','Нова','Во подготовка'].includes(order.status)))}>Само нови</button><button className="ghost" onClick={()=>setSelectedIds(new Set())}>Исчисти</button></div><div className="planner-grid"><PlannerItem title={productName('p025')} needed={totals.p025} stock={state.warehouse.p025.total} remaining={remaining.p025} perPackage={15}/><PlannerItem title={productName('p15')} needed={totals.p15} stock={state.warehouse.p15.total} remaining={remaining.p15} perPackage={6}/><PlannerItem title="Флаери" needed={totals.flyers} stock={state.warehouse.flyers} remaining={remaining.flyers} perPackage={0}/></div></Card>}
  <div className="toolbar"><div className="search"><Search size={18}/><input placeholder="Пребарај клиент, град или број..." value={query} onChange={event=>setQuery(event.target.value)}/></div></div>
  <Card>{list.length===0?<Empty text={emptyText}/>:<div className={`orders-list${view==='loading'?' planner-orders':''}`}>{list.map((order:Order)=><article className={order.status==='Чека залиха'?'waiting-order':''} key={order.id} onClick={()=>onOpen(order.id)}>{view==='loading'&&<label className="load-check" onClick={event=>event.stopPropagation()}><input type="checkbox" checked={selectedIds.has(order.id)} onChange={()=>toggle(order.id)}/><span>{selectedIds.has(order.id)?'✓':''}</span></label>}<div className="order-main"><div className="order-number">{order.number}</div><h3>{order.client}</h3><p>{order.city} • {order.date}</p></div><div className="order-qty"><span>{productName('p025')} <b>{quantityBreakdown(orderPieces(order).p025,15)}</b></span><span>{productName('p15')} <b>{quantityBreakdown(orderPieces(order).p15,6)}</b></span><span>Флаери <b>{order.flyers} пар.</b></span></div><div className="order-actions"><span className={statusClass(order.status)}>{order.status}</span><button className="icon-btn" onClick={event=>{event.stopPropagation();onEdit(order)}}><Pencil size={17}/></button>{onDelete&&<button className="icon-btn danger" onClick={event=>{event.stopPropagation();onDelete(order.id)}}><Trash2 size={17}/></button>}<ChevronRight size={20}/></div></article>)}</div>}</Card></>
}
const PlannerItem=({title,needed,stock,remaining,perPackage}:{title:string;needed:number;stock:number;remaining:number;perPackage:number})=><div className={`planner-item${remaining<0?' shortage':''}`}><h4>{title}</h4><span>Потребно <b>{needed}</b><small>{quantityBreakdown(needed,perPackage)}</small></span><span>Во магацин <b>{stock}</b></span>{remaining>=0?<span>Ќе остане <b>{remaining}</b><small>{quantityBreakdown(remaining,perPackage)}</small></span>:<span>Недостига <b>{Math.abs(remaining)}</b><small>{quantityBreakdown(Math.abs(remaining),perPackage)}</small></span>}</div>

function Packing({order,orders,onSelect,patchPacked,changeStatus,advanceOrder,printOrder,onEdit,fromQr}:{order:Order|null;orders:Order[];onSelect:(id:string)=>void;patchPacked:(o:Order,key:keyof Order['packed'],value:boolean)=>void;changeStatus:(o:Order,s:OrderStatus)=>void;advanceOrder:(o:Order)=>void;printOrder:(o:Order)=>void;onEdit:(o:Order)=>void;fromQr:boolean}){
 if(!order)return <><PageHeader title="Пакување"/><Empty text="Нема нарачки за пакување."/></>
 const total025Packages=order.qty025+order.free025,total025Pieces=(order.qty025Pieces||0)+(order.free025Pieces||0),total15Packages=order.qty15+(order.free15||0),total15Pieces=(order.qty15Pieces||0)+(order.free15Pieces||0)
 const packageAmount=(packages:number,pieces:number)=>`${packages} пакети${pieces?` + ${pieces} парчиња`:''}`
 const groups=[['Чекаат залиха',orders.filter(o=>o.status==='Чека залиха')],['За пакување',orders.filter(o=>o.status==='Нова'||o.status==='Во подготовка')],['Спакувани',orders.filter(o=>o.status==='Спакувана')],['Излезени',orders.filter(o=>o.status==='Излезена')],['Испратени',orders.filter(o=>o.status==='Испратена')],['Доставени',orders.filter(o=>o.status==='Доставена')]] as const
 const statusOptions=[order.status,...allowedTransitions[order.status]],waitingForStock=order.status==='Чека залиха'
 const nextLabel:Partial<Record<OrderStatus,string>>={Нова:'Потврди цела нарачка → Спакувана','Во подготовка':'Потврди цела нарачка → Спакувана',Спакувана:'Следен статус → Испратена',Излезена:'Следен статус → Испратена',Испратена:'Следен статус → Доставена'}
 return <><PageHeader title="Пакување" action={<div className="packing-page-actions"><button className="ghost desktop-print-action" onClick={()=>printOrder(order)}><Printer size={18}/> Печати</button><PdfShareButton order={order} label="PDF / Печати" mobilePrint/></div>}/><div className="packing-layout">
  <Card className="order-selector"><h3>Патека на нарачки</h3>{groups.map(([label,list])=>list.length?<div className="order-group" key={label}><div className="order-group-label">{label}<b>{list.length}</b></div>{list.map(item=><button className={item.id===order.id?'selected':''} onClick={()=>onSelect(item.id)} key={item.id}><div><b>{item.client}</b><small>{item.number}</small></div><span className={statusClass(item.status)}>{item.status}</span></button>)}</div>:null)}</Card>
  <div className="packing-main"><Card className="packing-summary"><div><span>{order.number}</span><h2>{order.client}</h2><p>{order.city} • {order.date}</p></div><div className="packing-status-controls"><button className="ghost order-edit-action" onClick={()=>onEdit(order)}><Pencil size={17}/> Исправи</button><select aria-label="Статус на нарачка" value={order.status} onChange={e=>changeStatus(order,e.target.value as OrderStatus)}>{statusOptions.map(status=><option key={status}>{status}</option>)}</select></div></Card>
   {waitingForStock&&<div className="waiting-banner">Оваа нарачка чека залиха. Пакувањето ќе се отклучи автоматски кога ќе пристигне доволно стока.</div>}
   <Card className={`qr-order-panel${fromQr?' opened-from-qr':''}`}><div className="qr-order-copy"><QrCode/><div><span>{fromQr?'Отворено преку QR код':'QR код на спецификацијата'}</span><strong>Цела нарачка • еден QR код</strong><small>Провери ги производите подолу, па потврди го следниот статус.</small></div></div>{nextLabel[order.status]?<button className="primary qr-next-status" onClick={()=>advanceOrder(order)}>{nextLabel[order.status]} <ChevronRight size={18}/></button>:order.status==='Доставена'?<span className="workflow-complete"><CheckCircle2 size={17}/> Нарачката е доставена</span>:<span className="status">{order.status}</span>}</Card>
   <div className="pack-rows"><PackRowV2 checked={order.packed.regular025} disabled={order.stockDeducted||waitingForStock} onChange={value=>patchPacked(order,'regular025',value)} title={productName('p025')} qty={order.qty025} detail={breakdown(order.qty025,order.qty025Pieces||0)}/><PackRowV2 checked={order.packed.bib15} disabled={order.stockDeducted||waitingForStock} onChange={value=>patchPacked(order,'bib15',value)} title={productName('p15')} qty={order.qty15} detail={breakdown(order.qty15,order.qty15Pieces||0)}/><PackRowV2 checked={order.packed.free025} disabled={order.stockDeducted||waitingForStock} onChange={value=>patchPacked(order,'free025',value)} title={`Гратис ${productName('p025')}`} qty={order.free025} detail={`${breakdown(order.free025,order.free025Pieces||0)} • одделно`}/><PackRowV2 checked={Boolean(order.packed.free15)} disabled={order.stockDeducted||waitingForStock} onChange={value=>patchPacked(order,'free15',value)} title={`Гратис ${productName('p15')}`} qty={order.free15||0} detail={`${breakdown(order.free15||0,order.free15Pieces||0)} • одделно`}/><PackRowV2 checked={order.packed.flyers} disabled={order.stockDeducted||waitingForStock} onChange={value=>patchPacked(order,'flyers',value)} title="Флаери" qty={order.flyers} detail={`${order.flyers} парчиња`}/></div>
   <Card className="take-card"><div className="take-card-title"><WarehouseIcon/><span>Вкупно за земање од магацин</span></div><div className="take-list"><div><span>{productName('p025')}</span><strong>{packageAmount(total025Packages,total025Pieces)}</strong><small>редовни {order.qty025} пак. + гратис {order.free025} пак.</small></div><div><span>{productName('p15')}</span><strong>{packageAmount(total15Packages,total15Pieces)}</strong><small>редовни {order.qty15} пак. + гратис {order.free15||0} пак.</small></div><div><span>{productName('flyers')}</span><strong>{order.flyers} парчиња</strong><small>промотивен материјал</small></div></div></Card>
  </div>
 </div></>
}
const PackRowV2=({checked,disabled,onChange,title,qty,detail}:{checked:boolean;disabled:boolean;onChange:(value:boolean)=>void;title:string;qty:number;detail:string})=><label className={`pack-row ${checked?'done':''} ${disabled?'locked':''}`}><input type="checkbox" checked={checked} disabled={disabled} onChange={event=>onChange(event.target.checked)}/><div className="check-ui">{checked&&<CheckCircle2/>}</div><div><h3>{title}</h3><p>{detail}</p></div><strong>{qty}</strong></label>


type ReportPeriod='all'|'month'|'year'|'custom'
type ReportStatus='active'|'all'|OrderStatus
function ReportsPage({state}:{state:AppState}){
 const [period,setPeriod]=useState<ReportPeriod>('all')
 const [status,setStatus]=useState<ReportStatus>('active')
 const [client,setClient]=useState('all')
 const [city,setCity]=useState('all')
 const [query,setQuery]=useState('')
 const [fromDate,setFromDate]=useState('')
 const [toDate,setToDate]=useState('')
 const now=new Date();const monthPrefix=`${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}`;const yearPrefix=String(now.getFullYear())
 const clients=[...new Set(state.orders.map(order=>order.client.trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'mk'))
 const cities=[...new Set(state.orders.map(order=>order.city.trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'mk'))
 const inPeriod=(date:string)=>period==='all'||(period==='month'?date.startsWith(monthPrefix):period==='year'?date.startsWith(yearPrefix):(!fromDate||date>=fromDate)&&(!toDate||date<=toDate))
 const statusMatch=(order:Order)=>status==='all'||(status==='active'?order.status!=='Откажана':order.status===status)
 const orders=state.orders.filter(order=>inPeriod(order.date)&&statusMatch(order)&&(client==='all'||order.client===client)&&(city==='all'||order.city===city)&&(`${order.number} ${order.client} ${order.city}`.toLowerCase().includes(query.trim().toLowerCase()))).toSorted((a,b)=>b.date.localeCompare(a.date)||b.number.localeCompare(a.number))
 const reportRows=orders.map(order=>{
  const regular025=order.qty025*15+(order.qty025Pieces||0),gratis025=order.free025*15+(order.free025Pieces||0)
  const regular15=order.qty15*6+(order.qty15Pieces||0),gratis15=(order.free15||0)*6+(order.free15Pieces||0)
  return {order,regular025,gratis025,total025:regular025+gratis025,regular15,gratis15,total15:regular15+gratis15,flyers:order.flyers}
 })
 const totals=reportRows.reduce((sum,row)=>({regular025:sum.regular025+row.regular025,gratis025:sum.gratis025+row.gratis025,total025:sum.total025+row.total025,regular15:sum.regular15+row.regular15,gratis15:sum.gratis15+row.gratis15,total15:sum.total15+row.total15,flyers:sum.flyers+row.flyers}),{regular025:0,gratis025:0,total025:0,regular15:0,gratis15:0,total15:0,flyers:0})
 const clientRows=[...reportRows.reduce((map,row)=>{const key=row.order.client.trim()||'Без клиент';const current=map.get(key)||{client:key,orders:0,total025:0,gratis025:0,total15:0,gratis15:0,flyers:0};current.orders+=1;current.total025+=row.total025;current.gratis025+=row.gratis025;current.total15+=row.total15;current.gratis15+=row.gratis15;current.flyers+=row.flyers;map.set(key,current);return map},new Map<string,{client:string;orders:number;total025:number;gratis025:number;total15:number;gratis15:number;flyers:number}>()).values()].sort((a,b)=>(b.total025+b.total15+b.flyers)-(a.total025+a.total15+a.flyers))
 const resetFilters=()=>{setPeriod('all');setStatus('active');setClient('all');setCity('all');setQuery('');setFromDate('');setToDate('')}
 return <><PageHeader title="Целосен извештај"/><Card className="report-filters"><div className="report-toolbar"><label>Период<select value={period} onChange={event=>setPeriod(event.target.value as ReportPeriod)}><option value="all">Сите датуми</option><option value="month">Овој месец</option><option value="year">Оваа година</option><option value="custom">Избран период</option></select></label>{period==='custom'&&<><label>Од<input type="date" value={fromDate} onChange={event=>setFromDate(event.target.value)}/></label><label>До<input type="date" value={toDate} onChange={event=>setToDate(event.target.value)}/></label></>}<label>Статус<select value={status} onChange={event=>setStatus(event.target.value as ReportStatus)}><option value="active">Сите освен откажани</option><option value="all">Сите статуси</option><option value="Нова">Нова</option><option value="Во подготовка">Во подготовка</option><option value="Спакувана">Спакувана</option><option value="Излезена">Излезена</option><option value="Испратена">Испратена</option><option value="Доставена">Доставена</option><option value="Откажана">Откажана</option><option value="Чека залиха">Чека залиха</option></select></label><label>Клиент<select value={client} onChange={event=>setClient(event.target.value)}><option value="all">Сите клиенти</option>{clients.map(item=><option key={item}>{item}</option>)}</select></label><label>Град<select value={city} onChange={event=>setCity(event.target.value)}><option value="all">Сите градови</option>{cities.map(item=><option key={item}>{item}</option>)}</select></label><label className="report-search">Пребарај<input placeholder="Број, клиент или град" value={query} onChange={event=>setQuery(event.target.value)}/></label><button className="ghost" onClick={resetFilters}>Исчисти филтри</button></div></Card><div className="report-grid"><Card className="report-total"><span>Издадено {productName('p025')}</span><strong>{totals.total025} шишиња</strong><small>{Math.floor(totals.total025/15)} пак. + {totals.total025%15} пар. • гратис {totals.gratis025}</small></Card><Card className="report-total"><span>Издадено {productName('p15')}</span><strong>{totals.total15} БиБ</strong><small>{Math.floor(totals.total15/6)} пак. + {totals.total15%6} пар. • гратис {totals.gratis15}</small></Card><Card className="report-total"><span>Издадени флаери</span><strong>{totals.flyers}</strong><small>Вкупно парчиња</small></Card><Card className="report-total"><span>Нарачки во извештај</span><strong>{orders.length}</strong><small>Според избраните филтри</small></Card></div><Card><div className="section-title"><div><h3>Детален извештај по нарачка</h3><p>Редовна количина, гратис и вкупно издадено.</p></div></div>{reportRows.length===0?<Empty text="Нема нарачки за избраните филтри."/>:<div className="table-wrap"><table><thead><tr><th>Датум</th><th>Нарачка</th><th>Клиент</th><th>Град</th><th>Статус</th><th>0,250 редовно</th><th>0,250 гратис</th><th>0,250 вкупно</th><th>BiB редовно</th><th>BiB гратис</th><th>BiB вкупно</th><th>Флаери</th></tr></thead><tbody>{reportRows.map(({order,regular025,gratis025,total025,regular15,gratis15,total15,flyers})=><tr key={order.id}><td>{order.date}</td><td><b>{order.number}</b></td><td>{order.client}</td><td>{order.city}</td><td><span className={statusClass(order.status)}>{order.status}</span></td><td>{regular025}</td><td>{gratis025}</td><td><b>{total025}</b></td><td>{regular15}</td><td>{gratis15}</td><td><b>{total15}</b></td><td>{flyers}</td></tr>)}</tbody><tfoot><tr><th colSpan={5}>ВКУПНО</th><th>{totals.regular025}</th><th>{totals.gratis025}</th><th>{totals.total025}</th><th>{totals.regular15}</th><th>{totals.gratis15}</th><th>{totals.total15}</th><th>{totals.flyers}</th></tr></tfoot></table></div>}</Card><Card><div className="section-title"><div><h3>Збирно по клиент</h3><p>За брзо да видиш кој клиент колку добил и колку гратис му е дадено.</p></div></div>{clientRows.length===0?<Empty text="Нема податоци."/>:<div className="table-wrap"><table><thead><tr><th>Клиент</th><th>Нарачки</th><th>0,250 вкупно</th><th>0,250 гратис</th><th>BiB вкупно</th><th>BiB гратис</th><th>Флаери</th></tr></thead><tbody>{clientRows.map(row=><tr key={row.client}><td><b>{row.client}</b></td><td>{row.orders}</td><td>{row.total025}</td><td>{row.gratis025}</td><td>{row.total15}</td><td>{row.gratis15}</td><td>{row.flyers}</td></tr>)}</tbody></table></div>}</Card></>
}

function WarehousePage({state,onEntry,onReceipt,onEditReceipt}:{state:AppState;onEntry:()=>void;onReceipt:()=>void;onEditReceipt:(receipt:ReceiptGroup)=>void}){
 const receipts=receiptGroups(state.movements)
 const today=todayLocal()
 const todayReceipts=receipts.filter(receipt=>receipt.date===today)
 const todayLines=todayReceipts.flatMap(receipt=>receipt.lines)
 const today025=todayLines.filter(m=>m.product==='p025').reduce((a,m)=>({packages:a.packages+m.packages,pieces:a.pieces+m.pieces}),{packages:0,pieces:0})
 const today15=todayLines.filter(m=>m.product==='p15').reduce((a,m)=>({packages:a.packages+m.packages,pieces:a.pieces+m.pieces}),{packages:0,pieces:0})
 const todayFlyers=todayLines.filter(m=>m.product==='flyers').reduce((sum,m)=>sum+m.pieces,0)
 return <><PageHeader title="Магацин" action={<div className="page-actions"><button className="primary" onClick={onReceipt}><CirclePlus size={18}/> Нова приемница</button><button className="ghost" onClick={onEntry}><ArrowLeftRight size={18}/> Друго движење</button></div>}/><div className="stock-grid"><StockCard title={productName('p025')} packs={state.warehouse.p025.packages} pieces={state.warehouse.p025.pieces} total={state.warehouse.p025.total} reserved={reserved(state).p025} available={available(state).p025} perPackage={15}/><StockCard title={productName('p15')} packs={state.warehouse.p15.packages} pieces={state.warehouse.p15.pieces} total={state.warehouse.p15.total} reserved={reserved(state).p15} available={available(state).p15} perPackage={6}/><StockCard title={productName('flyers')} packs={0} pieces={state.warehouse.flyers} total={state.warehouse.flyers} reserved={reserved(state).flyers} available={available(state).flyers} perPackage={0}/></div><Card className="receipt-summary"><div className="section-title"><div><h3>Денес примено</h3><p>{today} • етикетирано и спакувано од работниците</p></div><span className="receipt-count">{todayReceipts.length} приемници</span></div><div className="receipt-metrics"><ReceiptMetric label={productName('p025')} value={`${today025.packages} пак.${today025.pieces?` + ${today025.pieces} пар.`:''}`}/><ReceiptMetric label={productName('p15')} value={`${today15.packages} пак.${today15.pieces?` + ${today15.pieces} пар.`:''}`}/><ReceiptMetric label={productName('flyers')} value={`${todayFlyers} пар.`}/></div></Card><Card><div className="section-title"><div><h3>Приемници за роба</h3><p>Сите производи од една приемница се прикажани заедно</p></div></div><ReceiptTable receipts={receipts} onEdit={onEditReceipt}/></Card><Card><div className="section-title"><div><h3>Последни движења</h3><p>Излези, корекции и враќања</p></div></div><MovementTable movements={state.movements.slice(0,8)}/></Card></>
}
const ReceiptMetric=({label,value}:{label:string;value:string})=><div><span>{label}</span><strong>{value}</strong></div>
const receiptItems=(receipt:ReceiptGroup)=>receipt.lines.map(line=>`${productName(line.product)}: ${line.product==='flyers'?`${line.pieces} пар.`:`${line.packages} пак.${line.pieces?` + ${line.pieces} пар.`:''}`}`).join(' • ')
const ReceiptTable=({receipts,onView,onEdit}:{receipts:ReceiptGroup[];onView?:(receipt:ReceiptGroup)=>void;onEdit?:(receipt:ReceiptGroup)=>void})=>receipts.length===0?<Empty text="Сè уште нема внесени приемници."/>:<div className="table-wrap"><table className="receipt-table"><thead><tr><th>Приемница</th><th>Датум</th><th>Производи и количини</th><th>Работници / тим</th><th>Забелешка</th>{(onView||onEdit)&&<th>Акции</th>}</tr></thead><tbody>{receipts.map(receipt=><tr key={receipt.number}><td><b>{receipt.number}</b></td><td>{receipt.date}</td><td>{receiptItems(receipt)}</td><td>{receipt.party||'—'}</td><td>{receipt.note||'—'}</td>{(onView||onEdit)&&<td><div className="archive-actions">{onView&&<button className="ghost compact-action" onClick={()=>onView(receipt)}><Eye size={16}/> Преглед</button>}{onEdit&&<button className="ghost compact-action" onClick={()=>onEdit(receipt)}><Pencil size={16}/> Измени</button>}</div></td>}</tr>)}</tbody></table></div>
function MovementsPage({state}:{state:AppState}){return <><PageHeader title="Историја на залиха"/><Card><MovementTable movements={state.movements}/></Card></>}
const MovementTable=({movements}:{movements:AppState['movements']})=>movements.length===0?<Empty text="Сè уште нема движења на залиха."/>:<div className="table-wrap"><table><thead><tr><th>Датум</th><th>Производ</th><th>Тип</th><th>Пакети</th><th>Парчиња</th><th>Клиент / тим</th><th>Документ / нарачка</th><th>Забелешка</th></tr></thead><tbody>{movements.map(m=><tr key={m.id}><td>{m.date}</td><td>{productName(m.product)}</td><td><span className="status">{m.type}</span></td><td>{m.packages}</td><td>{m.pieces}</td><td>{m.party||'—'}</td><td>{m.orderNumber||'—'}</td><td>{m.note||'—'}</td></tr>)}</tbody></table></div>
function PrintingPage({state,printOrder,printReceipt,changeStatus,editReceipt}:{state:AppState;printOrder:(order:Order)=>void;printReceipt:(receipt:ReceiptGroup)=>void;changeStatus:(order:Order,status:OrderStatus)=>void;editReceipt:(receipt:ReceiptGroup)=>void}){
 const [selectedReceipt,setSelectedReceipt]=useState<ReceiptGroup|null>(null)
 const [selectedOrder,setSelectedOrder]=useState<Order|null>(null)
 const receipts=receiptGroups(state.movements)
 const orders=[...state.orders].sort((a,b)=>b.number.localeCompare(a.number))
 const scrollTo=(id:string)=>document.getElementById(id)?.scrollIntoView({behavior:'smooth',block:'start'})
 return <><PageHeader title="Архива на документи"/><div className="archive-metrics"><button type="button" className="card archive-metric-link" onClick={()=>scrollTo('packing-archive')}><FileText/><span>Спецификации за пакување<strong>{orders.length}</strong><small>Отвори листа</small></span><ChevronRight/></button><button type="button" className="card archive-metric-link" onClick={()=>scrollTo('receipt-archive')}><ArchiveRestore/><span>Приемници за роба<strong>{receipts.length}</strong><small>Отвори листа</small></span><ChevronRight/></button></div><Card className="archive-card"><div id="packing-archive" className="archive-anchor"/><div className="section-title"><div><h3>Спецификации за пакување</h3><p>Преглед, печатење и споделување PDF на Viber</p></div></div>{orders.length===0?<Empty text="Нема спецификации за пакување."/>:<><div className="table-wrap archive-desktop"><table><thead><tr><th>Број</th><th>Датум на нарачка</th><th>Клиент</th><th>Град</th><th>Статус</th><th>Акции</th></tr></thead><tbody>{orders.map(order=><tr key={order.id}><td><b>{packingNumber(order)}</b></td><td>{order.date}</td><td>{order.client}</td><td>{order.city}</td><td><span className={statusClass(order.status)}>{order.status}</span></td><td><div className="archive-actions"><button className="ghost compact-action" onClick={()=>setSelectedOrder(order)}><Eye size={16}/> Преглед</button><button className="ghost compact-action" onClick={()=>printOrder(order)}><Printer size={16}/> Печати</button><PdfShareButton order={order} compact/></div></td></tr>)}</tbody></table></div><div className="archive-mobile-list">{orders.map(order=><article key={order.id}><div><span>{packingNumber(order)}</span><strong>{order.client}</strong><small>{order.city} • {order.date}</small></div><span className={statusClass(order.status)}>{order.status}</span><div className="archive-actions"><button className="ghost" onClick={()=>setSelectedOrder(order)}><Eye size={16}/> Преглед</button><button className="ghost" onClick={()=>printOrder(order)}><Printer size={16}/> Печати</button><PdfShareButton order={order}/></div></article>)}</div></>}</Card><Card className="archive-card"><div id="receipt-archive" className="archive-anchor"/><div className="section-title"><div><h3>Приемници за роба</h3><p>Целосна архива на примена и изработена роба</p></div></div><div className="archive-desktop"><ReceiptTable receipts={receipts} onView={setSelectedReceipt} onEdit={editReceipt}/></div><div className="archive-mobile-list">{receipts.map(receipt=><article key={receipt.number}><div><span>{receipt.number}</span><strong>{receipt.party||'Почетна состојба'}</strong><small>{receipt.date} • {receiptItems(receipt)}</small></div><div className="archive-actions"><button className="ghost" onClick={()=>setSelectedReceipt(receipt)}><Eye size={16}/> Преглед</button><button className="ghost" onClick={()=>editReceipt(receipt)}><Pencil size={16}/> Измени</button></div></article>)}</div></Card>{selectedOrder&&<OrderDetails order={selectedOrder} onClose={()=>setSelectedOrder(null)} onPrint={()=>printOrder(selectedOrder)} onStatus={status=>{changeStatus(selectedOrder,status);setSelectedOrder(null)}}/>} {selectedReceipt&&<ReceiptDetails receipt={selectedReceipt} onClose={()=>setSelectedReceipt(null)} onPrint={()=>printReceipt(selectedReceipt)}/>}</>
}
function PdfShareButton({order,compact=false,label='PDF / Viber',mobilePrint=false}:{order:Order;compact?:boolean;label?:string;mobilePrint?:boolean}){const [busy,setBusy]=useState(false);return <button type="button" className={`viber-action${compact?' compact-action':''}${mobilePrint?' packing-mobile-print':''}`} disabled={busy} onClick={async()=>{setBusy(true);try{const result=await shareOrderPdf(order);if(result==='downloaded')alert('PDF-от е симнат. Отвори го за печатење или прикачи го во Viber.')}catch(error){if(error instanceof DOMException&&error.name==='AbortError')return;alert(error instanceof Error?error.message:'Не може да се создаде PDF.')}finally{setBusy(false)}}}>{mobilePrint?<Printer size={16}/>:<Send size={16}/>} {busy?'Се подготвува...':label}</button>}
function OrderDetails({order,onClose,onPrint,onStatus}:{order:Order;onClose:()=>void;onPrint:()=>void;onStatus:(status:OrderStatus)=>void}){const rows=[[productName('p025'),order.qty025,order.qty025Pieces||0],[productName('p15'),order.qty15,order.qty15Pieces||0],[`Гратис ${productName('p025')}`,order.free025,order.free025Pieces||0],[`Гратис ${productName('p15')}`,order.free15||0,order.free15Pieces||0],[productName('flyers'),0,order.flyers]] as const;return <Modal title={`Нарачка ${order.number}`} onClose={onClose}><div className="receipt-detail order-detail"><div className="receipt-detail-meta"><span>Клиент <b>{order.client}</b></span><span>Град <b>{order.city}</b></span><span>Датум <b>{order.date}</b></span><span>Статус <select value={order.status} onChange={event=>onStatus(event.target.value as OrderStatus)}>{[order.status,...allowedTransitions[order.status]].map(status=><option key={status}>{status}</option>)}</select></span></div><div className="table-wrap"><table><thead><tr><th>Производ</th><th>Пакети</th><th>Парчиња</th></tr></thead><tbody>{rows.map(([name,packages,pieces])=><tr key={name}><td>{name}</td><td>{packages}</td><td>{pieces}</td></tr>)}</tbody></table></div><p className="receipt-detail-note"><b>Забелешка:</b> {order.note||'—'}</p><div className="modal-actions"><button className="ghost" onClick={onClose}>Затвори</button><button className="ghost" onClick={onPrint}><Printer size={17}/> Печати</button><PdfShareButton order={order}/></div></div></Modal>}
function ReceiptDetails({receipt,onClose,onPrint}:{receipt:ReceiptGroup;onClose:()=>void;onPrint:()=>void}){return <Modal title={`Приемница ${receipt.number}`} onClose={onClose}><div className="receipt-detail"><div className="receipt-detail-meta"><span>Датум <b>{receipt.date}</b></span><span>Работници / тим <b>{receipt.party||'—'}</b></span></div><div className="table-wrap"><table><thead><tr><th>Производ</th><th>Пакети</th><th>Парчиња</th></tr></thead><tbody>{receipt.lines.map(line=><tr key={line.id}><td>{productName(line.product)}</td><td>{line.packages}</td><td>{line.pieces}</td></tr>)}</tbody></table></div><p className="receipt-detail-note"><b>Забелешка:</b> {receipt.note||'—'}</p><div className="modal-actions"><button className="ghost" onClick={onClose}>Затвори</button><button className="primary" onClick={onPrint}><Printer size={17}/> Печати приемница</button></div></div></Modal>}
function SettingsPage({onReset,syncStatus,syncError,email,role,isAdmin,openAdmin}:{onReset?:()=>void;syncStatus:SyncStatus;syncError:string;email:string;role:'admin'|'operator';isAdmin:boolean;openAdmin:()=>void}){const labels:Record<SyncStatus,string>={loading:'Се вчитува...',offline:'Не е поврзано',syncing:'Се зачувува...',synced:'Синхронизирано',error:'Грешка во синхронизација'};return <><PageHeader title="Поставки"/><Card className="settings-card">{syncStatus==='error'?<CloudOff/>:<Cloud/>}<div><h3>Онлајн синхронизација</h3><p><b>{labels[syncStatus]}</b> • {email}{syncError&&<><br/><small>{syncError}</small></>}</p></div><button className="ghost" onClick={()=>void supabase.auth.signOut()}><LogOut size={18}/> Одјави се</button></Card><Card className="settings-card"><ShieldCheck/><div><h3>Кориснички профил</h3><p>Улога: <b>{isAdmin?'Администратор':role==='admin'?'Администратор':'Оператор'}</b>{isAdmin?' • Имаш целосни права.':' • Работиш во заедничкиот магацин.'}</p></div>{isAdmin&&<button className="ghost" onClick={openAdmin}>Отвори администрација</button>}</Card>{onReset&&<Card className="settings-card"><ArchiveRestore/><div><h3>Демо податоци</h3><p>Врати ја почетната залиха, клиентите и осумте демо нарачки.</p></div><button className="danger-btn" onClick={onReset}><RotateCcw size={18}/> Ресетирај демо податоци</button></Card>}<Card className="settings-card"><Truck/><div><h3>Автоматско ажурирање</h3><p>Апликацијата сама ја презема најновата верзија. Тековна верзија: <b>{appVersion}</b></p></div></Card></>}

type OrderFormValues={client:string;city:string;p025:string;e025:string;p15:string;e15:string;free025:string;free025Pieces:string;free15:string;free15Pieces:string;flyers:string;note:string}
const orderFormValues=(order?:Order|null):OrderFormValues=>({client:order?.client||'',city:order?.city||'',p025:String(order?.qty025||0),e025:String(order?.qty025Pieces||0),p15:String(order?.qty15||0),e15:String(order?.qty15Pieces||0),free025:String(order?.free025||0),free025Pieces:String(order?.free025Pieces||0),free15:String(order?.free15||0),free15Pieces:String(order?.free15Pieces||0),flyers:String(order?.flyers||0),note:order?.note||''})

function NewOrder({state,onClose,onSave}:{state:AppState;onClose:()=>void;onSave:(o:Order)=>void}){return <OrderEditor state={state} onClose={onClose} onSave={onSave}/>}
function EditOrder({state,order,onClose,onSave}:{state:AppState;order:Order;onClose:()=>void;onSave:(o:Order)=>void}){return <OrderEditor state={state} initial={order} onClose={onClose} onSave={onSave}/>}

function OrderEditor({state,initial,onClose,onSave}:{state:AppState;initial?:Order;onClose:()=>void;onSave:(o:Order)=>void}){
 const initialClient=state.clients.find(client=>client.name.trim().toLowerCase()===initial?.client.trim().toLowerCase())
 const [clientId,setClientId]=useState(initialClient?.id||'')
 const [f,setF]=useState<OrderFormValues>(()=>orderFormValues(initial))
 const [showPieces,setShowPieces]=useState(Boolean((initial?.qty025Pieces||0)+(initial?.qty15Pieces||0)+(initial?.free025Pieces||0)+(initial?.free15Pieces||0)))
 const draft:Order={id:initial?.id||'draft',number:initial?.number||makeOrderNumber(state.orders),client:f.client.trim(),city:f.city.trim(),date:initial?.date||todayLocal(),qty025:+f.p025,qty025Pieces:+f.e025,qty15:+f.p15,qty15Pieces:+f.e15,free025:+f.free025,free025Pieces:+f.free025Pieces,free15:+f.free15,free15Pieces:+f.free15Pieces,flyers:+f.flyers,note:f.note.trim(),status:initial?.status||'Нова',packed:initial?.packed||{regular025:false,bib15:false,free025:false,free15:false,flyers:false},stockDeducted:Boolean(initial?.stockDeducted)}
 const capacityState=initial?{...state,orders:state.orders.filter(order=>order.id!==initial.id)}:state
 const shortage=reservationShortage(capacityState,draft)
 const hasItems=draft.qty025+(draft.qty025Pieces||0)+draft.qty15+(draft.qty15Pieces||0)+draft.free025+(draft.free025Pieces||0)+(draft.free15||0)+(draft.free15Pieces||0)+draft.flyers>0
 const stockValid=canReserveOrder(capacityState,draft)
 const valid=hasItems
 const chooseClient=(id:string)=>{setClientId(id);const client=state.clients.find(item=>item.id===id);if(client)setF(current=>({...current,client:client.name,city:client.city}));else if(id==='new')setF(current=>({...current,client:'',city:''}))}
 return <Modal title={initial?`Исправка на ${initial.number}`:'Нова нарачка'} onClose={onClose}><form onSubmit={event=>{event.preventDefault();if(valid)onSave({...draft,id:initial?.id||crypto.randomUUID()})}} className="form-grid order-form">
  <div className="form-section-title"><span>1</span><div><strong>Клиент</strong><small>Избери постоен клиент за автоматски да се пополни градот.</small></div></div>
  <Field label="Постоен клиент"><select value={clientId} onChange={event=>chooseClient(event.target.value)}><option value="">Избери клиент...</option>{state.clients.map(client=><option key={client.id} value={client.id}>{client.name} - {client.city}</option>)}<option value="new">+ Нов клиент</option></select></Field>
  <div/>
  <Field label="Клиент"><input required value={f.client} onChange={event=>setF({...f,client:event.target.value})}/></Field>
  <Field label="Град"><input required value={f.city} onChange={event=>setF({...f,city:event.target.value})}/></Field>
  <div className="form-section-title"><span>2</span><div><strong>Производи</strong><small>Главно внесувај пакети; парчиња користи само кога има остаток.</small></div></div>
  <Field label={`Пакети ${productName('p025')}`}><input min="0" type="number" inputMode="numeric" value={f.p025} onChange={event=>setF({...f,p025:event.target.value})}/></Field>
  <Field label={`Пакети ${productName('p15')}`}><input min="0" type="number" inputMode="numeric" value={f.p15} onChange={event=>setF({...f,p15:event.target.value})}/></Field>
  <Field label={`Гратис пакети ${productName('p025')}`}><input min="0" type="number" inputMode="numeric" value={f.free025} onChange={event=>setF({...f,free025:event.target.value})}/></Field>
  <Field label={`Гратис пакети ${productName('p15')}`}><input min="0" type="number" inputMode="numeric" value={f.free15} onChange={event=>setF({...f,free15:event.target.value})}/></Field>
  <Field label="Флаери (парчиња)"><input min="0" type="number" inputMode="numeric" value={f.flyers} onChange={event=>setF({...f,flyers:event.target.value})}/></Field>
  <Field label="Забелешка"><textarea value={f.note} onChange={event=>setF({...f,note:event.target.value})}/></Field>
  <button type="button" className="ghost optional-toggle" onClick={()=>setShowPieces(value=>!value)}>{showPieces?'Сокриј дополнителни парчиња':'+ Додај дополнителни парчиња'}</button>
  {showPieces&&<><Field label={`Парчиња ${productName('p025')}`}><input min="0" max="14" type="number" inputMode="numeric" value={f.e025} onChange={event=>setF({...f,e025:event.target.value})}/></Field><Field label={`Парчиња ${productName('p15')}`}><input min="0" max="5" type="number" inputMode="numeric" value={f.e15} onChange={event=>setF({...f,e15:event.target.value})}/></Field><Field label="Гратис парчиња Шише"><input min="0" max="14" type="number" inputMode="numeric" value={f.free025Pieces} onChange={event=>setF({...f,free025Pieces:event.target.value})}/></Field><Field label="Гратис парчиња БиБ"><input min="0" max="5" type="number" inputMode="numeric" value={f.free15Pieces} onChange={event=>setF({...f,free15Pieces:event.target.value})}/></Field></>}
  <div className="calc-banner"><b>Редовно:</b> {productName('p025')} {f.p025} пак. + {f.e025} пар. • {productName('p15')} {f.p15} пак. + {f.e15} пар.<br/><b>Гратис:</b> Шише {f.free025} пак. + {f.free025Pieces} пар. • БиБ {f.free15} пак. + {f.free15Pieces} пар.</div>
  {!hasItems?<div className="stock-validation error"><CloudOff size={18}/> Внеси барем еден производ.</div>:stockValid?<div className="stock-validation ok"><CheckCircle2 size={18}/>Количината е достапна и ќе биде резервирана.</div>:<div className="stock-validation warning"><CloudOff size={18}/><span>Нарачката ќе се зачува со статус „Чека залиха“ и ќе биде на врвот на листата.{shortage.p025>0&&` ${productName('p025')}: недостигаат ${shortage.p025}.`}{shortage.p15>0&&` ${productName('p15')}: недостигаат ${shortage.p15}.`}{shortage.flyers>0&&` Флаери: недостигаат ${shortage.flyers}.`}</span></div>}
  <div className="modal-actions"><button type="button" className="ghost" onClick={onClose}>Откажи</button><button className="primary" disabled={!valid}>{initial?'Зачувај исправка':'Зачувај нарачка'}</button></div>
 </form></Modal>
}
function StockEntry({onClose,onSave}:{onClose:()=>void;onSave:(p:ProductKey,t:MovementType,pack:number,pieces:number,party:string,note:string,date:string)=>void}){const [f,setF]=useState({product:'p025' as ProductKey,type:'Корекција' as MovementType,packages:'0',pieces:'0',party:'',note:'',doc:'',date:new Date().toISOString().slice(0,10)});return <Modal title="Друго движење на залиха" onClose={onClose}><form className="form-grid" onSubmit={e=>{e.preventDefault();onSave(f.product,f.type,+f.packages,+f.pieces,f.party,`${f.doc?`Документ: ${f.doc}. `:''}${f.note}`,f.date)}}><Field label="Производ"><select value={f.product} onChange={e=>setF({...f,product:e.target.value as ProductKey})}><option value="p025">{productName('p025')}</option><option value="p15">{productName('p15')}</option><option value="flyers">Флаери</option></select></Field><Field label="Тип"><select value={f.type} onChange={e=>setF({...f,type:e.target.value as MovementType})}>{['Излез','Корекција','Враќање','Оштетување'].map(x=><option key={x}>{x}</option>)}</select></Field><Field label="Пакети"><input type="number" min="0" value={f.packages} disabled={f.product==='flyers'} onChange={e=>setF({...f,packages:e.target.value})}/></Field><Field label="Индивидуални парчиња"><input type="number" min="0" value={f.pieces} onChange={e=>setF({...f,pieces:e.target.value})}/></Field><Field label="Добавувач / клиент"><input value={f.party} onChange={e=>setF({...f,party:e.target.value})}/></Field><Field label="Документ / фактура"><input value={f.doc} onChange={e=>setF({...f,doc:e.target.value})}/></Field><Field label="Датум"><input type="date" value={f.date} onChange={e=>setF({...f,date:e.target.value})}/></Field><Field label="Забелешка"><textarea value={f.note} onChange={e=>setF({...f,note:e.target.value})}/></Field><div className="modal-actions"><button type="button" className="ghost" onClick={onClose}>Откажи</button><button className="primary">Зачувај движење</button></div></form></Modal>}

function EditReceipt({receipt,onClose,onSave}:{receipt:ReceiptGroup;onClose:()=>void;onSave:(receipt:ReceiptGroup,lines:Movement[],workers:string,note:string,date:string)=>void}){
 const [date,setDate]=useState(receipt.date)
 const [workers,setWorkers]=useState(receipt.party)
 const [note,setNote]=useState(receipt.note)
 const [lines,setLines]=useState(()=>receipt.lines.map(line=>({...line})))
 const updateLine=(id:string,patch:Partial<Movement>)=>setLines(current=>current.map(line=>line.id===id?{...line,...patch}:line))
 return <Modal title={`Измени приемница ${receipt.number}`} onClose={onClose}><form className="form-grid" onSubmit={event=>{event.preventDefault();onSave(receipt,lines,workers.trim(),note.trim(),date)}}><div className="receipt-number-banner"><span>Број на приемница</span><strong>{receipt.number}</strong></div><Field label="Датум на прием"><input type="date" required value={date} onChange={event=>setDate(event.target.value)}/></Field><Field label="Работници / тим"><input required value={workers} onChange={event=>setWorkers(event.target.value)}/></Field><div className="table-wrap"><table><thead><tr><th>Производ</th><th>Пакети</th><th>Парчиња</th></tr></thead><tbody>{lines.map(line=><tr key={line.id}><td>{productName(line.product)}</td><td><input aria-label={`Пакети ${productName(line.product)}`} type="number" min="0" disabled={line.product==='flyers'} value={line.packages} onChange={event=>updateLine(line.id,{packages:+event.target.value})}/></td><td><input aria-label={`Парчиња ${productName(line.product)}`} type="number" min="0" value={line.pieces} onChange={event=>updateLine(line.id,{pieces:+event.target.value})}/></td></tr>)}</tbody></table></div><Field label="Забелешка"><textarea value={note} onChange={event=>setNote(event.target.value)}/></Field><div className="calc-banner">При зачувување, старата количина автоматски се поништува, новата се додава и актуелната залиха се порамнува.</div><div className="modal-actions"><button type="button" className="ghost" onClick={onClose}>Откажи</button><button className="primary"><Pencil size={17}/> Зачувај измена</button></div></form></Modal>
}
function ReceiptEntry({state,onClose,onSave}:{state:AppState;onClose:()=>void;onSave:(p:ProductKey,pack:number,pieces:number,workers:string,note:string,date:string)=>void}){const [f,setF]=useState({product:'p025' as ProductKey,packages:'0',pieces:'0',workers:'',note:'',date:todayLocal()});const number=makeReceiptNumber(state.movements);return <Modal title="Нова приемница за роба" onClose={onClose}><form className="form-grid" onSubmit={e=>{e.preventDefault();onSave(f.product,+f.packages,+f.pieces,f.workers.trim(),f.note.trim(),f.date)}}><div className="receipt-number-banner"><span>Број на приемница</span><strong>{number}</strong></div><Field label="Производ"><select value={f.product} onChange={e=>setF({...f,product:e.target.value as ProductKey})}><option value="p025">{productName('p025')}</option><option value="p15">{productName('p15')}</option><option value="flyers">Флаери</option></select></Field><Field label="Датум на прием"><input type="date" required value={f.date} onChange={e=>setF({...f,date:e.target.value})}/></Field><Field label="Завршени пакети"><input type="number" min="0" required value={f.packages} disabled={f.product==='flyers'} onChange={e=>setF({...f,packages:e.target.value})}/></Field><Field label="Дополнителни парчиња"><input type="number" min="0" required value={f.pieces} onChange={e=>setF({...f,pieces:e.target.value})}/></Field><Field label="Работници / тим"><input required placeholder="Имиња или смена" value={f.workers} onChange={e=>setF({...f,workers:e.target.value})}/></Field><Field label="Забелешка"><textarea placeholder="Етикетирање, пакување или друга забелешка" value={f.note} onChange={e=>setF({...f,note:e.target.value})}/></Field><div className="calc-banner">Со зачувување, количината автоматски се додава во магацинот и останува запишана во дневната евиденција.</div><div className="modal-actions"><button type="button" className="ghost" onClick={onClose}>Откажи</button><button className="primary">Зачувај приемница</button></div></form></Modal>}
function ReceiptPrint({receipt}:{receipt:ReceiptGroup}){const total=(line:Movement)=>line.product==='p025'?line.packages*15+line.pieces:line.product==='p15'?line.packages*6+line.pieces:line.pieces;return <div className="print-sheet"><header className="packing-print-head"><h1>ПРИЕМНИЦА ЗА РОБА</h1></header><section className="packing-print-meta"><div><span>Број на приемница</span><strong>{receipt.number}</strong></div><div className="packing-client"><span>Работници / тим</span><strong>{receipt.party||'—'}</strong></div><div><span>Датум</span><b>{receipt.date}</b></div><div><span>Тип</span><b>Прием на готова роба</b></div></section><table className="packing-print-table"><thead><tr><th>Производ</th><th>Пакети</th><th>Парчиња</th><th>Вкупно единици</th></tr></thead><tbody>{receipt.lines.map(line=><tr key={line.id}><td><strong>{productName(line.product)}</strong></td><td>{line.packages}</td><td>{line.pieces}</td><td><strong>{total(line)}</strong></td></tr>)}</tbody></table><section className="packing-notes"><span>Забелешка</span><p>{receipt.note||'________________________________________________________________'}</p></section><div className="packing-sign"><span>Предал / примил</span><i/></div></div>}
function PackingPrint({o,qrDataUrl}:{o:Order;qrDataUrl:string}){
 const format=(value:number)=>String(value).replace(/\B(?=(\d{3})+(?!\d))/g,'.')
 const packageQuantity=(packages:number,pieces:number)=>`${packages} пакети${pieces?` + ${pieces} парчиња`:''}`
 const regular025Pieces=o.qty025*15+(o.qty025Pieces||0)
 const bib15Pieces=o.qty15*6+(o.qty15Pieces||0)
 const free025Pieces=o.free025*15+(o.free025Pieces||0)
 const free15Pieces=(o.free15||0)*6+(o.free15Pieces||0)
 const packingResult=(packages:number,extraPieces:number,perPackage:number,total:number,unit:string)=>`${packages} × ${perPackage}${extraPieces?` + ${extraPieces}`:''} = ${format(total)} ${unit}`
 return <div className="print-sheet">
  <header className="packing-print-head"><h1>СПЕЦИФИКАЦИЈА ЗА ПАКУВАЊЕ</h1>{qrDataUrl&&<img className="packing-order-qr" src={qrDataUrl} alt="QR код за нарачката"/>}</header>
  <section className="packing-print-meta"><div><span>Број на спецификација</span><strong>{packingNumber(o)}</strong></div><div className="packing-client"><span>Клиент</span><strong>{o.client}</strong></div><div><span>Датум</span><b>{formatDocumentDate(o.date)}</b></div><div><span>Град</span><b>{o.city}</b></div></section>
  <table className="packing-print-table"><thead><tr><th>Производ</th><th>Количина</th><th>Бр. во пакет</th><th>Пакување</th></tr></thead><tbody>
   <tr><td><strong>{productName('p025')}</strong></td><td>{packageQuantity(o.qty025,o.qty025Pieces||0)}</td><td>15 шишиња</td><td><strong>{packingResult(o.qty025,o.qty025Pieces||0,15,regular025Pieces,'шишиња')}</strong></td></tr>
   <tr><td><strong>{productName('p15')}</strong></td><td>{packageQuantity(o.qty15,o.qty15Pieces||0)}</td><td>6 БиБ</td><td><strong>{packingResult(o.qty15,o.qty15Pieces||0,6,bib15Pieces,'БиБ')}</strong></td></tr>
   <tr><td><strong>Гратис {productName('p025')}</strong><small>Се пакува одделно</small></td><td>{packageQuantity(o.free025,o.free025Pieces||0)}</td><td>15 шишиња</td><td><strong>{packingResult(o.free025,o.free025Pieces||0,15,free025Pieces,'шишиња')}</strong><small>ОДДЕЛНО</small></td></tr>
   <tr><td><strong>Гратис {productName('p15')}</strong><small>Се пакува одделно</small></td><td>{packageQuantity(o.free15||0,o.free15Pieces||0)}</td><td>6 БиБ</td><td><strong>{packingResult(o.free15||0,o.free15Pieces||0,6,free15Pieces,'БиБ')}</strong><small>ОДДЕЛНО</small></td></tr>
   <tr><td><strong>{productName('flyers')}</strong></td><td>{format(o.flyers)} парчиња</td><td>—</td><td><strong>{format(o.flyers)} парчиња</strong></td></tr>
  </tbody></table>
  <section className="packing-notes"><span>Забелешка</span><p>{o.note||'________________________________________________________________'}</p></section>
  <div className="packing-sign"><span>Спакувал</span><i/></div>
 </div>
}
export default App
